64	static int parse_int(const char *s, const char *opt) {
65	    char *end = NULL;
66	    long v = strtol(s, &end, 10);
67	    if (s[0] == '\0' || *end != '\0' || v <= 0 || v > INT_MAX) {
68	        fprintf(stderr, "ds4-bench: invalid value for %s: %s\n", opt, s);
69	        exit(2);
70	    }
71	    return (int)v;
72	}
