74	static int parse_nonnegative_int(const char *s, const char *opt) {
75	    char *end = NULL;
76	    long v = strtol(s, &end, 10);
77	    if (s[0] == '\0' || *end != '\0' || v < 0 || v > INT_MAX) {
78	        fprintf(stderr, "ds4-bench: invalid value for %s: %s\n", opt, s);
79	        exit(2);
80	    }
81	    return (int)v;
82	}
