84	static double parse_double_arg(const char *s, const char *opt) {
85	    char *end = NULL;
86	    double v = strtod(s, &end);
87	    if (s[0] == '\0' || *end != '\0' || !isfinite(v)) {
88	        fprintf(stderr, "ds4-bench: invalid value for %s: %s\n", opt, s);
89	        exit(2);
90	    }
91	    return v;
