102	static ds4_backend parse_backend(const char *s, const char *opt) {
103	    if (!strcmp(s, "metal")) return DS4_BACKEND_METAL;
104	#ifdef DS4_ROCM_BUILD
105	    if (!strcmp(s, "rocm")) return DS4_BACKEND_CUDA;
106	#else
107	    if (!strcmp(s, "cuda")) return DS4_BACKEND_CUDA;
108	#endif
109	    if (!strcmp(s, "cpu")) return DS4_BACKEND_CPU;
110	    fprintf(stderr, "ds4-bench: invalid value for %s: %s\n", opt, s);
111	#ifdef DS4_ROCM_BUILD
112	    fprintf(stderr, "ds4-bench: valid backends are: metal, rocm, cpu\n");
113	#else
114	    fprintf(stderr, "ds4-bench: valid backends are: metal, cuda, cpu\n");
115	#endif
116	    exit(2);
117	}
