129	static char *read_file(const char *path) {
130	    FILE *fp = fopen(path, "rb");
131	    if (!fp) {
132	        fprintf(stderr, "ds4-bench: failed to open %s: %s\n", path, strerror(errno));
133	        exit(1);
134	    }
135	    if (fseek(fp, 0, SEEK_END) != 0) {
136	        fprintf(stderr, "ds4-bench: failed to seek %s\n", path);
137	        fclose(fp);
138	        exit(1);
139	    }
140	    long n = ftell(fp);
141	    if (n < 0) {
142	        fprintf(stderr, "ds4-bench: failed to tell %s\n", path);
143	        fclose(fp);
144	        exit(1);
145	    }
146	    if (fseek(fp, 0, SEEK_SET) != 0) {
147	        fprintf(stderr, "ds4-bench: failed to rewind %s\n", path);
148	        fclose(fp);
149	        exit(1);
150	    }
151	    char *buf = malloc((size_t)n + 1);
152	    if (!buf) {
153	        fprintf(stderr, "ds4-bench: out of memory reading %s\n", path);
154	        fclose(fp);
155	        exit(1);
156	    }
157	    if (fread(buf, 1, (size_t)n, fp) != (size_t)n) {
158	        fprintf(stderr, "ds4-bench: failed to read %s\n", path);
159	        free(buf);
160	        fclose(fp);
161	        exit(1);
162	    }
163	    fclose(fp);
164	    buf[n] = '\0';
165	    return buf;
166	}
