168	static bench_config parse_options(int argc, char **argv) {
169	    bench_config c = {
170	        .model_path = "ds4flash.gguf",
171	        .system = "You are a helpful assistant.",
172	        .backend = default_backend(),
173	        .ctx_start = 2048,
174	        .ctx_max = 32768,
175	        .step_incr = 2048,
176	        .gen_tokens = 128,
177	        .step_mul = 1.0,
178	    };
179	
180	    for (int i = 1; i < argc; i++) {
181	        const char *arg = argv[i];
182	        if (!strcmp(arg, "-h") || !strcmp(arg, "--help")) {
183	            const char *topic = (i + 1 < argc && argv[i + 1][0] != '-') ?
184	                argv[i + 1] : NULL;
185	            usage(stdout, topic);
186	            exit(0);
187	        }
188	        char dist_parse_err[256] = {0};
189	        ds4_dist_cli_parse_result dist_parse =
190	            ds4_dist_parse_cli_arg(arg,
191	                                   &i,
192	                                   argc,
193	                                   argv,
194	                                   &c.dist,
195	                                   dist_parse_err,
196	                                   sizeof(dist_parse_err));
197	        if (dist_parse == DS4_DIST_CLI_ERROR) {
198	            fprintf(stderr,
199	                    "ds4-bench: %s\n",
200	                    dist_parse_err[0] ? dist_parse_err : "invalid distributed option");
201	            exit(2);
202	        }
203	        if (dist_parse == DS4_DIST_CLI_MATCHED) continue;
204	
205	        if (!strcmp(arg, "-m") || !strcmp(arg, "--model")) {
206	            c.model_path = need_arg(&i, argc, argv, arg);
207	        } else if (!strcmp(arg, "--prompt-file")) {
208	            c.prompt_path = need_arg(&i, argc, argv, arg);
209	        } else if (!strcmp(arg, "--chat-prompt-file")) {
210	            c.chat_prompt_path = need_arg(&i, argc, argv, arg);
211	        } else if (!strcmp(arg, "-sys") || !strcmp(arg, "--system")) {
212	            c.system = need_arg(&i, argc, argv, arg);
213	        } else if (!strcmp(arg, "--ctx-start")) {
214	            c.ctx_start = parse_int(need_arg(&i, argc, argv, arg), arg);
215	        } else if (!strcmp(arg, "--ctx-max")) {
216	            c.ctx_max = parse_int(need_arg(&i, argc, argv, arg), arg);
217	        } else if (!strcmp(arg, "--ctx-alloc")) {
218	            c.ctx_alloc = parse_int(need_arg(&i, argc, argv, arg), arg);
219	        } else if (!strcmp(arg, "--step-incr")) {
220	            c.step_incr = parse_int(need_arg(&i, argc, argv, arg), arg);
221	        } else if (!strcmp(arg, "--step-mul")) {
222	            c.step_mul = parse_double_arg(need_arg(&i, argc, argv, arg), arg);
223	        } else if (!strcmp(arg, "--gen-tokens") || !strcmp(arg, "--tokens") || !strcmp(arg, "-n")) {
224	            c.gen_tokens = parse_nonnegative_int(need_arg(&i, argc, argv, arg), arg);
225	        } else if (!strcmp(arg, "--csv")) {
226	            c.csv_path = need_arg(&i, argc, argv, arg);
227	        } else if (!strcmp(arg, "--dump-frontier-logits-dir")) {
228	            c.dump_frontier_logits_dir = need_arg(&i, argc, argv, arg);
229	        } else if (!strcmp(arg, "--expert-profile")) {
230	            c.expert_profile_path = need_arg(&i, argc, argv, arg);
231	        } else if (!strcmp(arg, "-t") || !strcmp(arg, "--threads")) {
232	            c.threads = parse_int(need_arg(&i, argc, argv, arg), arg);
233	        } else if (!strcmp(arg, "--backend")) {
234	            c.backend = parse_backend(need_arg(&i, argc, argv, arg), arg);
235	        } else if (!strcmp(arg, "--metal")) {
236	            c.backend = DS4_BACKEND_METAL;
237	#ifdef DS4_ROCM_BUILD
238	        } else if (!strcmp(arg, "--rocm")) {
239	            c.backend = DS4_BACKEND_CUDA;
240	#else
241	        } else if (!strcmp(arg, "--cuda")) {
242	            c.backend = DS4_BACKEND_CUDA;
243	#endif
244	        } else if (!strcmp(arg, "--cpu")) {
245	            c.backend = DS4_BACKEND_CPU;
246	        } else if (!strcmp(arg, "--quality")) {
247	            c.quality = true;
248	        } else if (!strcmp(arg, "--ssd-streaming")) {
249	            c.ssd_streaming = true;
250	        } else if (!strcmp(arg, "--ssd-streaming-cold")) {
251	            c.ssd_streaming_cold = true;
252	        } else if (!strcmp(arg, "--ssd-streaming-cache-experts")) {
253	            uint32_t experts = 0;
254	            uint64_t bytes = 0;
255	            if (!ds4_parse_streaming_cache_experts_arg(
256	                    need_arg(&i, argc, argv, arg), &experts, &bytes)) {
257	                fprintf(stderr,
258	                        "ds4-bench: --ssd-streaming-cache-experts must be a positive count or <number>GB\n");
259	                exit(2);
260	            }
261	            c.ssd_streaming_cache_experts = experts;
262	            c.ssd_streaming_cache_bytes = bytes;
263	        } else if (!strcmp(arg, "--ssd-streaming-preload-experts")) {
264	            int v = parse_int(need_arg(&i, argc, argv, arg), arg);
265	            if (v <= 0) {
266	                fprintf(stderr, "ds4-bench: --ssd-streaming-preload-experts must be positive\n");
267	                exit(2);
268	            }
269	            c.ssd_streaming_preload_experts = (uint32_t)v;
270	        } else if (!strcmp(arg, "--simulate-used-memory")) {
271	            if (!ds4_parse_gib_arg(need_arg(&i, argc, argv, arg),
272	                                   &c.simulate_used_memory_bytes)) {
273	                fprintf(stderr,
274	                        "ds4-bench: --simulate-used-memory must be a positive GiB value, e.g. 64GB\n");
275	                exit(2);
276	            }
277	        } else if (!strcmp(arg, "--prefill-chunk")) {
278	            c.prefill_chunk = (uint32_t)parse_int(need_arg(&i, argc, argv, arg), arg);
279	        } else if (!strcmp(arg, "--power")) {
280	            c.power_percent = parse_int(need_arg(&i, argc, argv, arg), arg);
281	            if (c.power_percent < 1 || c.power_percent > 100) {
282	                fprintf(stderr, "ds4-bench: --power must be between 1 and 100\n");
283	                exit(2);
284	            }
285	        } else if (!strcmp(arg, "--warm-weights")) {
286	            c.warm_weights = true;
287	        } else {
288	            fprintf(stderr, "ds4-bench: unknown option: %s\n", arg);
289	            usage(stderr, NULL);
290	            exit(2);
291	        }
292	    }
293	
294	    if (!!c.prompt_path == !!c.chat_prompt_path) {
295	        fprintf(stderr, "ds4-bench: specify exactly one of --prompt-file or --chat-prompt-file\n");
296	        exit(2);
297	    }
298	    if (c.ctx_start > c.ctx_max) {
299	        fprintf(stderr, "ds4-bench: --ctx-start must be <= --ctx-max\n");
300	        exit(2);
301	    }
302	    if (c.step_mul < 1.0) {
303	        fprintf(stderr, "ds4-bench: --step-mul must be >= 1\n");
304	        exit(2);
305	    }
306	    if (c.step_mul == 1.0 && c.step_incr <= 0) {
307	        fprintf(stderr, "ds4-bench: --step-incr must be positive when --step-mul is 1\n");
308	        exit(2);
309	    }
310	    if (c.ctx_max > INT_MAX - c.gen_tokens - 1) {
311	        fprintf(stderr, "ds4-bench: requested context is too large\n");
312	        exit(2);
313	    }
314	    if (c.ctx_alloc == 0) c.ctx_alloc = c.ctx_max + c.gen_tokens + 1;
315	    if (c.ctx_alloc <= c.ctx_max + c.gen_tokens) {
316	        fprintf(stderr, "ds4-bench: --ctx-alloc must be greater than ctx-max + gen-tokens\n");
317	        exit(2);
318	    }
319	    char dist_err[256];
320	    if (ds4_dist_prepare_engine_options(&c.dist, NULL, dist_err, sizeof(dist_err)) != 0) {
321	        fprintf(stderr, "ds4-bench: %s\n", dist_err);
322	        exit(2);
323	    }
324	    if (c.dist.role == DS4_DISTRIBUTED_WORKER) {
325	        fprintf(stderr, "ds4-bench: --role worker is a serving mode; start workers with ./ds4\n");
326	        exit(2);
327	    }
328	    return c;
329	}
