331	static void json_write_string(FILE *fp, const char *s) {
332	    fputc('"', fp);
333	    if (s) {
334	        for (const unsigned char *p = (const unsigned char *)s; *p; p++) {
335	            switch (*p) {
336	            case '"':  fputs("\\\"", fp); break;
337	            case '\\': fputs("\\\\", fp); break;
338	            case '\b': fputs("\\b", fp); break;
339	            case '\f': fputs("\\f", fp); break;
340	            case '\n': fputs("\\n", fp); break;
341	            case '\r': fputs("\\r", fp); break;
342	            case '\t': fputs("\\t", fp); break;
343	            default:
344	                if (*p < 0x20) fprintf(fp, "\\u%04x", (unsigned)*p);
345	                else fputc((char)*p, fp);
346	                break;
347	            }
348	        }
349	    }
350	    fputc('"', fp);
351	}
