353	static int write_frontier_logits_json(
354	        const bench_config *cfg,
355	        ds4_engine         *engine,
356	        ds4_session        *session,
357	        int                 frontier,
358	        int                 previous) {
359	    if (!cfg->dump_frontier_logits_dir) return 0;
360	
361	    const int vocab = ds4_engine_vocab_size(engine);
362	    float *logits = malloc((size_t)vocab * sizeof(logits[0]));
363	    if (!logits) {
364	        fprintf(stderr, "ds4-bench: out of memory copying frontier logits\n");
365	        return 1;
366	    }
367	    if (ds4_session_copy_logits(session, logits, vocab) != vocab) {
368	        fprintf(stderr, "ds4-bench: failed to copy frontier logits at %d\n", frontier);
369	        free(logits);
370	        return 1;
371	    }
372	
373	    char path[PATH_MAX];
374	    const int n = snprintf(path,
375	                           sizeof(path),
376	                           "%s/frontier_%06d.logits.json",
377	                           cfg->dump_frontier_logits_dir,
378	                           frontier);
379	    if (n <= 0 || (size_t)n >= sizeof(path)) {
380	        fprintf(stderr, "ds4-bench: frontier logits path is too long\n");
381	        free(logits);
382	        return 1;
383	    }
384	
385	    FILE *fp = fopen(path, "wb");
386	    if (!fp) {
387	        fprintf(stderr, "ds4-bench: failed to open %s: %s\n", path, strerror(errno));
388	        free(logits);
389	        return 1;
390	    }
391	
392	    const int argmax = ds4_session_argmax(session);
393	    fprintf(fp, "{\n  \"source\":\"ds4-bench\",\n  \"model\":");
394	    json_write_string(fp, cfg->model_path);
395	    fprintf(fp,
396	            ",\n  \"backend\":\"%s\",\n  \"quality\":%s,\n"
397	            "  \"quant_bits\":%d,\n  \"prompt_tokens\":%d,\n"
398	            "  \"frontier_tokens\":%d,\n  \"prefill_tokens\":%d,\n"
399	            "  \"ctx\":%d,\n  \"vocab\":%d,\n"
400	            "  \"argmax_id\":%d,\n  \"argmax_logit\":%.9g,\n  \"logits\":[",
401	            ds4_backend_name(cfg->backend),
402	            cfg->quality ? "true" : "false",
403	            ds4_engine_routed_quant_bits(engine),
404	            frontier,
405	            frontier,
406	            frontier - previous,
407	            cfg->ctx_alloc,
408	            vocab,
409	            argmax,
410	            logits[argmax]);
411	    for (int i = 0; i < vocab; i++) {
412	        if (i) fputc(',', fp);
413	        if ((i % 8) == 0) fputs("\n    ", fp);
414	        if (isfinite(logits[i])) fprintf(fp, "%.9g", logits[i]);
415	        else fputs("null", fp);
416	    }
417	    fputs("\n  ]\n}\n", fp);
418	    if (fclose(fp) != 0) {
419	        fprintf(stderr, "ds4-bench: failed to close %s\n", path);
420	        free(logits);
421	        return 1;
422	    }
423	    free(logits);
424	    return 0;
425	}
