427	static int next_frontier(const bench_config *c, int cur) {
428	    if (cur >= c->ctx_max) return c->ctx_max;
429	    int next;
430	    if (c->step_mul == 1.0) {
431	        if (cur > INT_MAX - c->step_incr) next = c->ctx_max;
432	        else next = cur + c->step_incr;
433	    } else {
434	        const double v = ceil((double)cur * c->step_mul);
435	        next = v > (double)INT_MAX ? c->ctx_max : (int)v;
436	        if (next <= cur) next = cur + 1;
437	    }
438	    if (next > c->ctx_max) next = c->ctx_max;
439	    return next;
440	}
