459	static int wait_distributed_route(ds4_session *session) {
460	    char err[256] = {0};
461	    char last[256] = {0};
462	    unsigned ticks = 0;
463	    const struct timespec delay = {0, 250000000L};
464	
465	    for (;;) {
466	        int ready = ds4_session_distributed_route_ready(session, err, sizeof(err));
467	        if (ready > 0) {
468	            if (ticks) fprintf(stderr, "ds4-bench: distributed route ready\n");
469	            return 0;
470	        }
471	        if (ready < 0) {
472	            fprintf(stderr,
473	                    "ds4-bench: distributed route readiness failed: %s\n",
474	                    err[0] ? err : "unknown error");
475	            return 1;
476	        }
477	        const char *why = err[0] ? err : "route incomplete";
478	        if (strcmp(last, why) != 0 || (ticks % 20u) == 0) {
479	            fprintf(stderr, "ds4-bench: waiting for distributed route: %s\n", why);
480	            snprintf(last, sizeof(last), "%s", why);
481	        }
482	        nanosleep(&delay, NULL);
483	        ticks++;
484	    }
485	}
