487	static void maybe_warn_distributed_step_shape(const bench_config *cfg, ds4_session *session) {
488	    if (!cfg || !session || cfg->dist.role != DS4_DISTRIBUTED_COORDINATOR) return;
489	    uint32_t chunk = cfg->dist.prefill_chunk;
490	    if (chunk == 0) {
491	        const int cap = ds4_session_prefill_cap(session);
492	        if (cap > 0) chunk = (uint32_t)cap;
493	    }
494	    if (chunk == 0) return;
495	    if (cfg->step_mul == 1.0 &&
496	        cfg->step_incr > 0 &&
497	        (uint32_t)cfg->step_incr < chunk &&
498	        cfg->ctx_start < cfg->ctx_max)
499	    {
500	        fprintf(stderr,
501	                "ds4-bench: note: --step-incr=%d is smaller than distributed prefill chunk %u; "
502	                "suffix rows will not show multi-chunk pipeline overlap\n",
503	                cfg->step_incr,
504	                chunk);
505	    }
506	}
