508	int main(int argc, char **argv) {
509	    bench_config cfg = parse_options(argc, argv);
510	
511	    ds4_engine_options opt = {
512	        .model_path = cfg.model_path,
513	        .backend = cfg.backend,
514	        .n_threads = cfg.threads,
515	        .prefill_chunk = cfg.prefill_chunk,
516	        .ssd_streaming_cache_experts = cfg.ssd_streaming_cache_experts,
517	        .ssd_streaming_cache_bytes = cfg.ssd_streaming_cache_bytes,
518	        .ssd_streaming_preload_experts = cfg.ssd_streaming_preload_experts,
519	        .simulate_used_memory_bytes = cfg.simulate_used_memory_bytes,
520	        .power_percent = cfg.power_percent,
521	        .warm_weights = cfg.warm_weights,
522	        .quality = cfg.quality,
523	        .ssd_streaming = cfg.ssd_streaming,
524	        .ssd_streaming_cold = cfg.ssd_streaming_cold,
525	        .expert_profile_path = cfg.expert_profile_path,
526	        .distributed = cfg.dist,
527	    };
528	    char dist_err[256];
529	    if (ds4_dist_prepare_engine_options(&cfg.dist, &opt, dist_err, sizeof(dist_err)) != 0) {
530	        fprintf(stderr, "ds4-bench: %s\n", dist_err);
531	        return 2;
532	    }
533	    ds4_engine *engine = NULL;
534	    if (ds4_engine_open(&engine, &opt) != 0) return 1;
535	    log_context_memory(cfg.backend, cfg.ctx_alloc, cfg.prefill_chunk);
536	
537	    char *text = read_file(cfg.prompt_path ? cfg.prompt_path : cfg.chat_prompt_path);
538	    ds4_tokens prompt = {0};
539	    if (cfg.chat_prompt_path) {
540	        ds4_encode_chat_prompt(engine, cfg.system, text, DS4_THINK_NONE, &prompt);
541	    } else {
542	        ds4_tokenize_text(engine, text, &prompt);
543	    }
544	    free(text);
545	
546	    if (prompt.len < cfg.ctx_max) {
547	        fprintf(stderr,
548	                "ds4-bench: prompt has %d tokens, need at least --ctx-max=%d\n",
549	                prompt.len,
550	                cfg.ctx_max);
551	        ds4_tokens_free(&prompt);
552	        ds4_engine_close(engine);
553	        return 1;
554	    }
555	
556	    ds4_session *session = NULL;
557	    if (ds4_session_create(&session, engine, cfg.ctx_alloc) != 0) {
558	        fprintf(stderr, "ds4-bench: failed to create session\n");
559	        ds4_tokens_free(&prompt);
560	        ds4_engine_close(engine);
561	        return 1;
562	    }
563	    if (cfg.dist.role == DS4_DISTRIBUTED_COORDINATOR &&
564	        wait_distributed_route(session) != 0)
565	    {
566	        ds4_session_free(session);
567	        ds4_tokens_free(&prompt);
568	        ds4_engine_close(engine);
569	        return 1;
570	    }
571	    maybe_warn_distributed_step_shape(&cfg, session);
572	
573	    FILE *out = stdout;
574	    if (cfg.csv_path) {
575	        out = fopen(cfg.csv_path, "wb");
576	        if (!out) {
577	            fprintf(stderr, "ds4-bench: failed to open %s: %s\n", cfg.csv_path, strerror(errno));
578	            ds4_session_free(session);
579	            ds4_tokens_free(&prompt);
580	            ds4_engine_close(engine);
581	            return 1;
582	        }
583	    }
584	    fprintf(out, "ctx_tokens,prefill_tokens,prefill_tps,gen_tokens,gen_tps,kvcache_bytes\n");
585	    fflush(out);
586	
587	    const int eos = ds4_token_eos(engine);
588	    const bool distributed = cfg.dist.role == DS4_DISTRIBUTED_COORDINATOR;
589	    ds4_session_snapshot snap = {0};
590	    char err[256];
591	    int previous = 0;
592	    int rc = 0;
593	
594	    for (int frontier = cfg.ctx_start; ; frontier = next_frontier(&cfg, frontier)) {
595	        ds4_tokens prefix = {
596	            .v = prompt.v,
597	            .len = frontier,
598	            .cap = frontier,
599	        };
600	
601	        const double prefill_t0 = bench_now_sec();
602	        if (ds4_session_sync(session, &prefix, err, sizeof(err)) != 0) {
603	            fprintf(stderr, "ds4-bench: prefill to %d failed: %s\n", frontier, err);
604	            rc = 1;
605	            break;
606	        }
607	        const double prefill_t1 = bench_now_sec();
608	        const double prefill_sec = prefill_t1 - prefill_t0;
609	        const int prefill_tokens = frontier - previous;
610	
611	        if (write_frontier_logits_json(&cfg, engine, session, frontier, previous) != 0) {
612	            rc = 1;
613	            break;
614	        }
615	
616	        if (cfg.gen_tokens > 0 && !distributed) {
617	            if (ds4_session_save_snapshot(session, &snap, err, sizeof(err)) != 0) {
618	                fprintf(stderr, "ds4-bench: snapshot at %d failed: %s\n", frontier, err);
619	                rc = 1;
620	                break;
621	            }
622	        }
623	
624	        const double gen_t0 = bench_now_sec();
625	        for (int i = 0; i < cfg.gen_tokens; i++) {
626	            if (ds4_session_pos(session) + 1 >= ds4_session_ctx(session)) {
627	                fprintf(stderr, "ds4-bench: generation would exceed allocated context at frontier %d\n", frontier);
628	                rc = 1;
629	                break;
630	            }
631	            const int token = ds4_session_argmax_excluding(session, eos);
632	            if (token < 0) {
633	                fprintf(stderr, "ds4-bench: failed to choose non-EOS token at frontier %d\n", frontier);
634	                rc = 1;
635	                break;
636	            }
637	            if (ds4_session_eval(session, token, err, sizeof(err)) != 0) {
638	                fprintf(stderr, "ds4-bench: decode at frontier %d failed: %s\n", frontier, err);
639	                rc = 1;
640	                break;
641	            }
642	        }
643	        const double gen_t1 = bench_now_sec();
644	        if (rc != 0) break;
645	
646	        if (cfg.gen_tokens == 0) {
647	            /* Pure prefill benchmark: leave the live session at the frontier. */
648	        } else if (distributed) {
649	            if (ds4_session_sync(session, &prefix, err, sizeof(err)) != 0) {
650	                fprintf(stderr, "ds4-bench: distributed replay restore at %d failed: %s\n", frontier, err);
651	                rc = 1;
652	                break;
653	            }
654	        } else {
655	            if (ds4_session_load_snapshot(session, &snap, err, sizeof(err)) != 0) {
656	                fprintf(stderr, "ds4-bench: restore at %d failed: %s\n", frontier, err);
657	                rc = 1;
658	                break;
659	            }
660	        }
661	
662	        const double gen_sec = gen_t1 - gen_t0;
663	        fprintf(out,
664	                "%d,%d,%.2f,%d,%.2f,%llu\n",
665	                frontier,
666	                prefill_tokens,
667	                prefill_sec > 0.0 ? (double)prefill_tokens / prefill_sec : 0.0,
668	                cfg.gen_tokens,
669	                gen_sec > 0.0 ? (double)cfg.gen_tokens / gen_sec : 0.0,
670	                (unsigned long long)(distributed ? 0 : snap.len));
671	        fflush(out);
672	
673	        previous = frontier;
674	        if (frontier >= cfg.ctx_max) break;
675	    }
676	
677	    if (out != stdout) fclose(out);
678	    ds4_session_snapshot_free(&snap);
679	    ds4_session_free(session);
680	    ds4_tokens_free(&prompt);
681	    ds4_engine_close(engine);
682	    return rc;
683	}
